import{_ as a,o as r,c as e,a2 as o}from"./chunks/framework.Cd7uensT.js";const u=JSON.parse('{"title":"系统管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features/system-management.md","filePath":"guide/features/system-management.md","lastUpdated":1781664033000}'),d={name:"guide/features/system-management.md"};function n(l,t,s,i,h,g){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="系统管理" tabindex="-1">系统管理 <a class="header-anchor" href="#系统管理" aria-label="Permalink to &quot;系统管理&quot;">​</a></h1><h2 id="用户管理" tabindex="-1">用户管理 <a class="header-anchor" href="#用户管理" aria-label="Permalink to &quot;用户管理&quot;">​</a></h2><p>用户管理用于管理系统用户账号和权限。</p><h3 id="用户状态" tabindex="-1">用户状态 <a class="header-anchor" href="#用户状态" aria-label="Permalink to &quot;用户状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><strong>正常</strong></td><td>用户可正常登录系统并使用相应权限功能</td></tr><tr><td><strong>待审核</strong></td><td>新注册用户，等待管理员审核通过后方可登录</td></tr><tr><td><strong>已禁用</strong></td><td>账号被管理员禁用，无法登录系统</td></tr></tbody></table><h3 id="审核流程" tabindex="-1">审核流程 <a class="header-anchor" href="#审核流程" aria-label="Permalink to &quot;审核流程&quot;">​</a></h3><p>用户注册审核流程如下：</p><ol><li><strong>用户注册</strong>：新用户通过注册页面提交账号信息</li><li><strong>待审核状态</strong>：注册成功后，账号自动进入「待审核」状态</li><li><strong>管理员审核</strong>：管理员在「用户管理」页面查看待审核用户列表</li><li><strong>审核操作</strong>：管理员可「通过」或「驳回」注册申请，驳回需填写原因</li><li><strong>结果通知</strong>： <ul><li>审核通过：用户收到通知，账号状态变更为「正常」，可登录系统</li><li>审核驳回：用户收到通知及驳回原因，可根据原因修改后重新提交注册</li></ul></li></ol><h3 id="角色权限" tabindex="-1">角色权限 <a class="header-anchor" href="#角色权限" aria-label="Permalink to &quot;角色权限&quot;">​</a></h3><p>系统采用 RBAC（基于角色的访问控制）权限模型：</p><table tabindex="0"><thead><tr><th>角色</th><th>权限范围</th></tr></thead><tbody><tr><td><strong>管理员</strong></td><td>全部功能，包括系统设置、用户管理、数据管理、所有模块的增删改查</td></tr><tr><td><strong>运维人员</strong></td><td>设备管理（含导入导出、端口管理、接线管理）、工单处理（接单、处理、完成）</td></tr><tr><td><strong>普通用户</strong></td><td>查看权限（查看设备、工单、仪表盘等），可创建工单</td></tr></tbody></table><h3 id="角色管理" tabindex="-1">角色管理 <a class="header-anchor" href="#角色管理" aria-label="Permalink to &quot;角色管理&quot;">​</a></h3><ul><li><strong>自定义角色</strong>：支持管理员自定义角色，为不同岗位配置专属权限组合</li><li><strong>权限粒度</strong>：权限控制到页面级和操作级（新增、编辑、删除、查看、导入、导出）</li><li><strong>角色分配</strong>：在用户编辑页面勾选角色，支持一个用户拥有多个角色</li></ul><h2 id="系统设置" tabindex="-1">系统设置 <a class="header-anchor" href="#系统设置" aria-label="Permalink to &quot;系统设置&quot;">​</a></h2><p>系统设置用于配置系统全局参数和外观。</p><h3 id="设置项" tabindex="-1">设置项 <a class="header-anchor" href="#设置项" aria-label="Permalink to &quot;设置项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td><strong>站点名称</strong></td><td>系统浏览器标签页标题和页面左上角显示的名称</td></tr><tr><td><strong>Logo</strong></td><td>系统左上角显示的 Logo 图片，建议尺寸 120×40px，支持 PNG/SVG 格式</td></tr><tr><td><strong>空闲超时</strong></td><td>用户无操作后自动退出登录的时间，可选范围：15分钟、30分钟、60分钟、永不超时</td></tr><tr><td><strong>背景图片</strong></td><td>登录页的背景图片，支持 JPG/PNG 格式</td></tr><tr><td><strong>维护模式</strong></td><td>开启后系统仅管理员可登录，其他用户访问时显示维护提示页面</td></tr><tr><td><strong>登录限制</strong></td><td>可限制指定 IP 段或仅允许内网 IP 访问系统登录页</td></tr></tbody></table><h3 id="操作说明" tabindex="-1">操作说明 <a class="header-anchor" href="#操作说明" aria-label="Permalink to &quot;操作说明&quot;">​</a></h3><ol><li>进入「系统管理」→「系统设置」页面</li><li>修改配置项后点击「保存」按钮</li><li>部分设置（如站点名称、Logo、空闲超时）保存后立即生效</li><li>维护模式和登录限制等安全设置保存后，下一次登录时生效</li></ol>',19)])])}const c=a(d,[["render",n]]);export{u as __pageData,c as default};
